import java.nio.file.*;import java.sql.*;import java.util.regex.*;
public class MerchantProfilePermissionDiag{
 record DbConfig(String url,String username,String password){}
 public static void main(String[]args)throws Exception{DbConfig cfg=readDbConfig();try(Connection c=DriverManager.getConnection(cfg.url(),cfg.username(),cfg.password())){
  q(c,"menus", "select menu_id, parent_id, menu_name, path, component, menu_type, perms, tenant_id from sys_menu where path='profile' or component='merchant/profile' or perms like 'merchant:profile:%' order by menu_id");
  q(c,"merchantRoles", "select r.role_id,r.role_name,r.role_key,r.tenant_id,count(rm.menu_id) menu_count from sys_role r left join sys_role_menu rm on rm.role_id=r.role_id where lower(r.role_key) like '%merchant%' or lower(r.role_name) like '%merchant%' group by r.role_id,r.role_name,r.role_key,r.tenant_id order by r.tenant_id,r.role_id");
  q(c,"merchantUsers", "select u.user_id,u.user_name,u.tenant_id,array_agg(r.role_key order by r.role_key) roles from sys_user u join sys_tenant t on t.tenant_id=u.tenant_id left join sys_user_role ur on ur.user_id=u.user_id left join sys_role r on r.role_id=ur.role_id where t.tenant_type='MERCHANT' and u.del_flag='0' group by u.user_id,u.user_name,u.tenant_id order by u.create_time desc nulls last limit 8");
 }}
 static void q(Connection c,String name,String sql)throws Exception{System.out.println("-- "+name);try(Statement s=c.createStatement();ResultSet rs=s.executeQuery(sql)){ResultSetMetaData md=rs.getMetaData();int n=md.getColumnCount();while(rs.next()){StringBuilder b=new StringBuilder();for(int i=1;i<=n;i++){if(i>1)b.append(" | ");b.append(md.getColumnLabel(i)).append('=').append(rs.getString(i));}System.out.println(b);}}}
 static DbConfig readDbConfig()throws Exception{String yml=Files.readString(Path.of("bocoo-admin/src/main/resources/application-dev.yml"));Matcher m=Pattern.compile("url:\\s*(jdbc:postgresql:[^\\r\\n]+).*?username:\\s*([^\\r\\n]+).*?password:\\s*([^\\r\\n]+)",Pattern.DOTALL).matcher(yml);if(!m.find())throw new IllegalStateException("DB config not found");return new DbConfig(m.group(1).trim(),m.group(2).trim(),m.group(3).trim());}
}